func rangeTree(data []int) int {
	n := data[0]
	points := make([]int, n)
	copy(points, data[1:1+n])
	sort.Ints(points)
	lo, hi := data[1+n], data[2+n]
	left := sort.SearchInts(points, lo)
	right := sort.SearchInts(points, hi+1)
	return right - left
}

