import java.util.Arrays;

public class RangeTree {
    public static int rangeTree(int[] data) {
        int n = data[0];
        int[] points = Arrays.copyOfRange(data, 1, 1 + n);
        Arrays.sort(points);
        int lo = data[1 + n], hi = data[2 + n];

        int left = lowerBound(points, lo);
        int right = upperBound(points, hi);
        return right - left;
    }

    private static int lowerBound(int[] arr, int val) {
        int lo = 0, hi = arr.length;
        while (lo < hi) {
            int mid = (lo + hi) / 2;
            if (arr[mid] < val) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }

    private static int upperBound(int[] arr, int val) {
        int lo = 0, hi = arr.length;
        while (lo < hi) {
            int mid = (lo + hi) / 2;
            if (arr[mid] <= val) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }

    public static void main(String[] args) {
        System.out.println(rangeTree(new int[]{5, 1, 3, 5, 7, 9, 2, 6}));
        System.out.println(rangeTree(new int[]{4, 2, 4, 6, 8, 1, 10}));
        System.out.println(rangeTree(new int[]{3, 1, 2, 3, 10, 20}));
    }
}

fun rangeTree(data: IntArray): Int {
    val n = data[0]
    val points = data.sliceArray(1 until 1 + n).also { it.sort() }
    val lo = data[1 + n]; val hi = data[2 + n]
    val left = points.indexOfFirst { it >= lo }.let { if (it == -1) n else it }
    val right = points.indexOfLast { it <= hi }.let { if (it == -1) -1 else it }
    return if (right < left) 0 else right - left + 1
}

fun main() {
    println(rangeTree(intArrayOf(5, 1, 3, 5, 7, 9, 2, 6)))
    println(rangeTree(intArrayOf(4, 2, 4, 6, 8, 1, 10)))
    println(rangeTree(intArrayOf(3, 1, 2, 3, 10, 20)))
}

fn range_tree(data: &[i32]) -> i32 {
    let n = data[0] as usize;
    let mut points: Vec<i32> = data[1..1 + n].to_vec();
    points.sort();
    let lo = data[1 + n];
    let hi = data[2 + n];

    let left = points.partition_point(|&x| x < lo);
    let right = points.partition_point(|&x| x <= hi);
    (right - left) as i32
}

fn main() {
    println!("{}", range_tree(&[5, 1, 3, 5, 7, 9, 2, 6]));
    println!("{}", range_tree(&[4, 2, 4, 6, 8, 1, 10]));
    println!("{}", range_tree(&[3, 1, 2, 3, 10, 20]));
}

