func rangeTree(_ data: [Int]) -> Int {
    let n = data[0]
    let points = Array(data[1..<(1 + n)]).sorted()
    let lo = data[1 + n], hi = data[2 + n]
    var count = 0
    for p in points {
        if p >= lo && p <= hi { count += 1 }
    }
    return count
}

